// Shape the webhook body for the AI Agent node.
//
// History comes from the BROWSER (it already has the transcript), which keeps this
// flow stateless - no memory node, no session store. We fold the last few turns
// into the system message so the agent still follows the conversation.

const body = $input.first().json.body || {};
const message = (body.message || '').toString().trim();
const history = Array.isArray(body.history) ? body.history.slice(-6) : [];

const SYSTEM = `You are Aria, a friendly AI receptionist for Tertiary Infotech Academy.

You are SPOKEN ALOUD by a talking avatar, so:
- Reply in ONE short sentence. Two at the very most.
- Plain spoken English. No markdown, no bullets, no emoji, no URLs.
- Say numbers in words: "two days", "nine thirty in the morning".
- If you do not know, say so briefly and offer a colleague follow-up. Never invent a price, a date or a policy.

WHAT YOU KNOW
- The academy runs WSQ short courses in AI, automation and data.
- Classes run 9:30am to 6:30pm on weekdays at our training centre.
- Course fees vary; funding is available for eligible Singaporeans.
- To enrol, a learner registers on the website.`;

const transcript = history
  .map((h) => `${h.role === 'you' ? 'Visitor' : 'Aria'}: ${h.text}`)
  .join('\n');

return [{ json: {
  chatInput: message || 'Hello',
  system: transcript ? `${SYSTEM}\n\nCONVERSATION SO FAR\n${transcript}` : SYSTEM,
  warm: !!body.warm,
  started_at: Date.now(),  // the agent reports no timings, so we measure wall-clock ourselves
} }];

// The avatar SPEAKS this, so strip anything that does not read aloud: a stray asterisk
// becomes an audible "asterisk" in the browser's voice.
const res = $input.first().json;
const started = $('Build Prompt').first().json.started_at;

let reply = (res.output || '').toString();

reply = reply
  .replace(/[*_`#>]/g, '')
  .replace(/^\s*[-\u2022]\s*/gm, '')
  .replace(/https?:\/\/\S+/g, 'the link on our website')
  .replace(/\s+/g, ' ')
  .trim();

if (!reply) {
  reply = 'Sorry, I did not catch that. Could you say it again?';
}

// The agent does not break latency down by phase, so total_ms is wall-clock across
// the run - the lab SHOWS the latency rather than claiming it.
return [{ json: {
  reply,
  timing: {
    total_ms: started ? Date.now() - started : null,
    model_load_ms: null,
    prompt_ms: null,
    generate_ms: null,
    tokens: 0,
    prompt_tokens: 0,
  },
} }];
